"use client";

import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { format } from "date-fns";
import { pt } from "date-fns/locale";
import { getToken } from "@/app/lib/auth";
import { fetchAdminLogs, type LogSistemaItem } from "@/app/lib/admin";
import {
  AdminPageHeader,
  AdminCard,
  AdminSection,
  buildBreadcrumbs,
} from "@/app/admin/_components";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

const OPCOES_POR_PAGINA = [10, 25, 50, 100] as const;

function tryFormatJson(str: string | null): string {
  if (!str || !str.trim()) return "";
  try {
    const parsed = JSON.parse(str) as unknown;
    return JSON.stringify(parsed, null, 2);
  } catch {
    return str;
  }
}

function LogRow({
  log,
  expandedId,
  onToggle,
}: {
  log: LogSistemaItem;
  expandedId: number | null;
  onToggle: (id: number) => void;
}) {
  const isExpanded = expandedId === log.id;
  const jsonPretty = useMemo(() => tryFormatJson(log.jsonDados), [log.jsonDados]);

  return (
    <>
      <tr
        role="button"
        tabIndex={0}
        onClick={() => onToggle(log.id)}
        onKeyDown={(e) => e.key === "Enter" && onToggle(log.id)}
        className="border-b border-[#e7e5e4] cursor-pointer transition-colors hover:bg-[#fafaf9] dark:border-[#222] dark:hover:bg-[#0a0a0a]"
      >
        <td className="whitespace-nowrap px-4 py-3 tabular-nums text-[#57534e] dark:text-[#a3a3a3]">
          {log.timestamp
            ? format(new Date(log.timestamp), "dd/MM/yyyy HH:mm:ss", { locale: pt })
            : "—"}
        </td>
        <td className="px-4 py-3">
          <span className="rounded bg-[#f1f5f9] px-2 py-0.5 font-medium text-[#475569] dark:bg-[#222] dark:text-[#94a3b8]">
            {log.acao}
          </span>
        </td>
        <td className="px-4 py-3 text-[#57534e] dark:text-[#a3a3a3]">
          {log.userName ?? log.userId ?? "—"}
        </td>
        <td className="max-w-md px-4 py-3">
          {log.jsonDados ? (
            <span className="truncate block text-xs text-[#78716c] dark:text-[#666]">
              {log.jsonDados}
            </span>
          ) : (
            "—"
          )}
        </td>
        <td className="w-10 px-2 py-3 text-center">
          <span
            className="inline-block text-[#78716c] dark:text-[#666]"
            aria-hidden
          >
            {isExpanded ? "▼" : "▶"}
          </span>
        </td>
      </tr>
      {isExpanded && jsonPretty && (
        <tr className="border-b border-[#e7e5e4] bg-[#fafaf9] dark:border-[#222] dark:bg-[#0a0a0a]">
          <td colSpan={5} className="px-4 py-3">
            <div className="rounded-lg border border-[#e7e5e4] bg-white p-3 dark:border-[#333] dark:bg-[#111]">
              <p className="mb-1 text-xs font-semibold text-[#57534e] dark:text-[#888]">
                Dados (JSON)
              </p>
              <pre className="max-h-48 overflow-auto whitespace-pre-wrap break-all text-xs text-[#1c1917] dark:text-[#e5e5e5]">
                {jsonPretty}
              </pre>
            </div>
          </td>
        </tr>
      )}
    </>
  );
}

export default function AdminLogsPage() {
  const token = getToken();
  const [pagina, setPagina] = useState(1);
  const [itensPorPagina, setItensPorPagina] = useState(25);
  const [acaoFiltro, setAcaoFiltro] = useState("");
  const [expandedId, setExpandedId] = useState<number | null>(null);

  const { data, isLoading, isFetching } = useQuery({
    queryKey: ["admin", "logs", pagina, itensPorPagina, acaoFiltro.trim()],
    queryFn: () =>
      fetchAdminLogs(token!, {
        pagina,
        itensPorPagina,
        acao: acaoFiltro.trim() || undefined,
      }),
    enabled: !!token,
    staleTime: 20 * 1000,
  });

  const items: LogSistemaItem[] = data?.items ?? [];
  const totalRegistos = data?.totalRegistos ?? 0;
  const totalPaginas = Math.max(1, Math.ceil(totalRegistos / itensPorPagina));
  const loading = isLoading || isFetching;

  const handleToggleExpand = (id: number) => {
    setExpandedId((prev) => (prev === id ? null : id));
  };

  return (
    <motion.div
      initial={fadeInUp.initial}
      animate={fadeInUp.animate}
      transition={transitionSmooth}
      className="space-y-6"
    >
      <AdminPageHeader
        title="Logs do sistema"
        description="Auditoria de ações (encomendas, stock, etc.). Ordenado por data decrescente. Clique numa linha para expandir os dados JSON."
        breadcrumb={buildBreadcrumbs("/admin/logs")}
      />

      <AdminSection
        title="Filtros"
        description="Refine a lista por tipo de ação."
      >
        <div className="flex flex-wrap items-center gap-4">
          <label className="flex items-center gap-2">
            <span className="text-sm font-medium text-[#57534e] dark:text-[#888]">
              Ação:
            </span>
            <input
              type="search"
              value={acaoFiltro}
              onChange={(e) => {
                setAcaoFiltro(e.target.value);
                setPagina(1);
              }}
              placeholder="ex.: ENCOMENDA_ACEITE"
              className="w-48 rounded-xl border border-[#e7e5e4] bg-white px-3 py-2 text-sm text-[#1c1917] placeholder:text-[#a8a29e] focus:border-[#f97316] focus:outline-none focus:ring-2 focus:ring-[#f97316]/20 dark:border-[#333] dark:bg-[#111] dark:text-white dark:placeholder:text-[#555]"
            />
          </label>
          <label className="flex items-center gap-2">
            <span className="text-sm font-medium text-[#57534e] dark:text-[#888]">
              Itens por página:
            </span>
            <select
              value={itensPorPagina}
              onChange={(e) => {
                setItensPorPagina(Number(e.target.value));
                setPagina(1);
              }}
              className="rounded-xl border border-[#e7e5e4] bg-white px-3 py-2 text-sm text-[#1c1917] focus:border-[#f97316] focus:outline-none dark:border-[#333] dark:bg-[#111] dark:text-white"
            >
              {OPCOES_POR_PAGINA.map((n) => (
                <option key={n} value={n}>
                  {n}
                </option>
              ))}
            </select>
          </label>
          <span className="text-sm text-[#78716c] dark:text-[#666]">
            {totalRegistos} registo(s)
          </span>
        </div>
      </AdminSection>

      <AdminCard padding={false} className="overflow-hidden">
        {loading && items.length === 0 ? (
          <div className="flex justify-center py-16">
            <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
          </div>
        ) : items.length === 0 ? (
          <p className="py-12 text-center text-sm text-[#78716c] dark:text-[#888]">
            Nenhum log encontrado.
          </p>
        ) : (
          <>
            <div className="overflow-x-auto">
              <table className="w-full min-w-[600px] text-left text-sm">
                <thead>
                  <tr className="border-b border-[#e7e5e4] bg-[#fafaf9] dark:border-[#222] dark:bg-[#0a0a0a]">
                    <th className="px-4 py-3 font-semibold text-[#57534e] dark:text-[#888]">
                      Data
                    </th>
                    <th className="px-4 py-3 font-semibold text-[#57534e] dark:text-[#888]">
                      Ação
                    </th>
                    <th className="px-4 py-3 font-semibold text-[#57534e] dark:text-[#888]">
                      Utilizador
                    </th>
                    <th className="px-4 py-3 font-semibold text-[#57534e] dark:text-[#888]">
                      Dados
                    </th>
                    <th className="w-10" />
                  </tr>
                </thead>
                <tbody>
                  {items.map((log) => (
                    <LogRow
                      key={log.id}
                      log={log}
                      expandedId={expandedId}
                      onToggle={handleToggleExpand}
                    />
                  ))}
                </tbody>
              </table>
            </div>
            {totalPaginas > 1 && (
              <div className="flex flex-wrap items-center justify-between gap-4 border-t border-[#e7e5e4] px-4 py-3 dark:border-[#222]">
                <p className="text-sm text-[#78716c] dark:text-[#666]">
                  Página {pagina} de {totalPaginas}
                </p>
                <div className="flex gap-2">
                  <button
                    type="button"
                    onClick={() => setPagina((p) => Math.max(1, p - 1))}
                    disabled={pagina <= 1 || loading}
                    className="rounded-xl border border-[#e7e5e4] bg-white px-4 py-2 text-sm font-medium text-[#57534e] disabled:opacity-50 dark:border-[#333] dark:bg-[#111] dark:text-[#a3a3a3]"
                  >
                    Anterior
                  </button>
                  <button
                    type="button"
                    onClick={() => setPagina((p) => Math.min(totalPaginas, p + 1))}
                    disabled={pagina >= totalPaginas || loading}
                    className="rounded-xl border border-[#e7e5e4] bg-white px-4 py-2 text-sm font-medium text-[#57534e] disabled:opacity-50 dark:border-[#333] dark:bg-[#111] dark:text-[#a3a3a3]"
                  >
                    Seguinte
                  </button>
                </div>
              </div>
            )}
          </>
        )}
      </AdminCard>
    </motion.div>
  );
}
